import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty / base premiums
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("quote for a single plain sword (no modifiers) yields 105 G");
  it.todo("quote for a single plain amulet yields 65 G");
  it.todo("quote for a single plain staff yields 85 G");
  it.todo("quote for a single plain potion yields 45 G");
  it.todo("quote for 2 runes yields 55 G (2 x 25 + 5 fee)");
  it.todo("quote for 3 runes yields 65 G (block of 3 = 60 + 5 fee)");
  it.todo("quote for 4 runes yields 105 G (no block, 4 x 25 + 5 fee)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G (two separate blocks)");
  it.todo("quote for a sword and amulet yields 165 G (sum of base premiums + fee)");

  // Premium modifiers
  it.todo("cursed sword adds 50% surcharge to that item: 100 + 50 + 5 = 155 G");
  it.todo("high enchantment (>=5) sword adds 30% surcharge: 100 + 30 + 5 = 135 G");
  it.todo("enchantment 4 sword does not trigger high-enchantment surcharge");
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("first insurance surcharge adds 10% per item");
  it.todo("follow-up contract gives 15% discount on policy base");
  it.todo("newcomer with cursed sword: 165 G integration example");
  it.todo("long-standing customer second contract integration example: 160 G");

  // Rounding
  it.todo("premium rounds up to whole G in MHPCO's favor");

  // Claims
  it.todo("claim with no damage on sword policy: payout 0, cap remains full");
  it.todo("standard claim: steel sword damage 500 → payout 400, cap 1600");
  it.todo("claim on rune (no enchantment/material): damage 200 → payout 100");
  it.todo("dragon-material sword fully reimbursed minus deductible");
  it.todo("high-enchantment (>=8) item reimbursed at 50% then deductible");
  it.todo("dragon-material + high-enchantment: 50% rule wins (400 G on 1000 G damage)");
  it.todo("deductible applies per damage event (multiple items)");
  it.todo("payout rounds down in MHPCO's favor");
  it.todo("cap exhaustion: successive claims limited by remaining cap");
  it.todo("multiple items of same type: each damage entry has own deductible");

  // Errors
  it.todo("unknown item type in quote → CLI exits non-zero");
  it.todo("claim damage references item not in policy → CLI exits non-zero");
  it.todo("damage entries exceeding insured count → CLI exits non-zero");
  it.todo("negative damage amount → CLI exits non-zero");
});

