const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  steps: QuoteStep[];
}

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
    return { premium: base + PROCESSING_FEE };
  });
  return { results };
};

